  ('heelevel3-8b44517b-moex-00145', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-112-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '依據政府資訊公開法，關於政府資訊公開，下列敘述何者錯誤？', '["政府資訊可由政府機關主動公開，亦得應人民申請被動公開", "申請政府資訊之公開，不以主張或維護法律上利益有必要為前提", "對於政府資訊公開申請之決定不服者，得依法提起行政救濟", "經申請公開之政府資訊涉及第三人權益，經其明確表示不同意公開時，政府機關應即作成不予 公開之決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:11+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "313", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
